B.L8=s(["Gire pesco\xe7o, ombros, quadril, joelhos e tornozelos sem pressa.","Movimentos amplos e suaves, sem for\xe7ar.","Objetivo: soltar as articula\xe7\xf5es e elevar a temperatura do corpo."],t.s)
B.I9=new A.bl("aquecimento-articular",B.L8,"Aquecimento articular",B.c9)
B.OF=s(["Deitado de bru\xe7os, bra\xe7os estendidos \xe0 frente.","Eleve bra\xe7os, peito e pernas ao mesmo tempo, contraindo as costas.","Segure 2 segundos no topo e des\xe7a devagar.","Sem for\xe7ar o pesco\xe7o \u2014 olhar para o ch\xe3o."],t.s)
B.Ib=new A.bl("superman",B.OF,"Superman",B.iP)
B.MA=s(["Deite sob uma mesa firme e segure a borda com as duas m\xe3os.","Corpo reto, calcanhares no ch\xe3o.","Puxe o peito em dire\xe7\xe3o \xe0 mesa, juntando as esc\xe1pulas.","Des\xe7a controlando. Quanto mais horizontal o corpo, mais dif\xedcil."],t.s)
B.IE=new A.bl("remada-mesa",B.MA,"Remada na mesa (australiana)",B.iP)
B.M9=s(["De bru\xe7os, eleve bra\xe7o direito e perna esquerda juntos.","Alterne com o lado oposto, como se nadasse.","Movimento cont\xednuo e controlado, abd\xf4men firme."],t.s)
B.I8=new A.bl("nadador",B.M9,"Nadador",B.iP)
B.M8=s(["Sente na beirada de uma cadeira firme, m\xe3os ao lado do quadril.","Deslize o corpo \xe0 frente e des\xe7a dobrando os cotovelos para tr\xe1s.","Cotovelos apontando para tr\xe1s (n\xe3o para os lados).","Suba empurrando com os tr\xedceps. Pernas mais estendidas = mais dif\xedcil."],t.s)
B.IB=new A.bl("mergulho-cadeira",B.M8,"Mergulho na cadeira (tr\xedceps)",B.iQ)
B.Ng=s(["Segure uma toalha com uma m\xe3o por baixo e pise/segure a outra ponta.","Puxe como uma rosca de b\xedceps, resistindo com a outra ponta.","Segure a contra\xe7\xe3o por 10\u201320 segundos e troque o bra\xe7o."],t.s)
B.Ih=new A.bl("rosca-isometrica",B.Ng,"Rosca isom\xe9trica com toalha",B.iQ)
B.OC=s(["Apoie as m\xe3os numa superf\xedcie elevada (mesa, sof\xe1, parede).","Corpo reto da cabe\xe7a aos calcanhares, abd\xf4men firme.","Des\xe7a o peito em dire\xe7\xe3o ao apoio e empurre de volta.","Quanto mais alto o apoio, mais f\xe1cil \u2014 comece confort\xe1vel."],t.s)
B.Io=new A.bl("flexao-inclinada",B.OC,"Flex\xe3o inclinada",B.cp)
