B.Is=new A.bl("flexao-declinada",B.MM,"Flex\xe3o declinada",B.cp)
B.Oj=s(["M\xe3os bem afastadas; des\xe7a deslocando o peso para um lado.",'Um bra\xe7o dobra, o outro estica ("como um arqueiro").',"Alterne os lados a cada repeti\xe7\xe3o."],t.s)
